import React from 'react';
import Container from 'react-bootstrap/Container';
import Row from 'react-bootstrap/Row';
import Title from './Title';

function Home() {
  return (
    <Container fluid className="main">
      <Row className="tag justify-content-center">
        <Title />
      </Row>
    </Container>
  )
}

export default Home;
